esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Cache write errors counter (cumulative)
| WHERE COALESCE(metrics.storage_cache_writes_err, storage_cache_writes_err) IS NOT NULL
// Detect increase in errors over the window
| STATS min_err = MIN(COALESCE(metrics.storage_cache_writes_err, storage_cache_writes_err)),
    max_err = MAX(COALESCE(metrics.storage_cache_writes_err, storage_cache_writes_err))
  BY host.name
| EVAL error_increase = max_err - min_err
// Alert when any new cache write errors occurred
| WHERE error_increase > 0
